import json
import subprocess
import sys
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent.parent
SCRIPT = REPO_ROOT / "scripts" / "apply-verdicts.py"
SCHEMAS = REPO_ROOT / "schemas"


def _run(args: list[str]) -> subprocess.CompletedProcess:
    return subprocess.run(
        [sys.executable, str(SCRIPT), *args],
        capture_output=True,
        text=True,
    )


def _finding(
    *,
    chash: str,
    title: str,
    runtime_scope: str = "service-internal",
    failure_mode: str = "degraded-behavior",
    evidence_quality: str = "demonstrated",
    trace_origin: str = "component",
) -> dict:
    return {
        "content_hash": chash,
        "concern_slug": "implementation",
        "source_dimensions": ["x"],
        "title": title,
        "runtime_scope": runtime_scope,
        "runtime_scope_justification": "test",
        "failure_mode": failure_mode,
        "failure_mode_justification": "test",
        "evidence_quality": evidence_quality,
        "evidence_quality_justification": "test",
        "trace_origin": trace_origin,
        "trace_origin_justification": "test",
        "effort_to_fix": "small",
        "effort_to_fix_justification": "test",
        "locations": [{"path": "src/a.py", "line": "1", "role": "primary"}],
        "issue": "i",
        "why_it_matters": "w",
        "suggested_fix": "s",
    }


def _write_stage_dir(stage_dir: Path, findings: list[dict]) -> None:
    stage_dir.mkdir(parents=True, exist_ok=True)
    envelope = {
        "project": {"name": "myapp", "scope_slug": ""},
        "decomposition": [
            {"dimension_name": "x", "dimension_slug": "x", "dimension_scope": {}},
        ],
        "issues": [],
    }
    with (stage_dir / "_envelope.json").open("w", encoding="utf-8") as fh:
        json.dump(envelope, fh)
    for f in findings:
        with (stage_dir / f"{f['content_hash']}.json").open("w", encoding="utf-8") as fh:
            json.dump(f, fh)


def _write_verdicts(verdicts_dir: Path, verdicts: list[dict]) -> None:
    verdicts_dir.mkdir(parents=True, exist_ok=True)
    batch = {"batch_number": 1, "verdicts": verdicts}
    with (verdicts_dir / "batch-1-output.json").open("w", encoding="utf-8") as fh:
        json.dump(batch, fh)


def _load_stage(stage_dir: Path) -> tuple[dict, list[dict]]:
    with (stage_dir / "_envelope.json").open("r", encoding="utf-8") as fh:
        envelope = json.load(fh)
    findings = []
    for p in sorted(stage_dir.glob("*.json")):
        if p.name == "_envelope.json":
            continue
        with p.open("r", encoding="utf-8") as fh:
            findings.append(json.load(fh))
    return envelope, findings


class TestApplyVerdicts:
    def test_confirm_passes_through_unchanged(self, tmp_path: Path):
        f = _finding(chash="aaaaaaaaaaaaaaaa", title="keep me")
        _write_stage_dir(tmp_path / "10-merged", [f])
        _write_verdicts(tmp_path / "15-validation", [
            {"finding_ref": {"content_hash": "aaaaaaaaaaaaaaaa"}, "action": "confirm", "reasoning": "ok"},
        ])
        out = tmp_path / "20-findings"
        out.mkdir()
        result = _run([
            "--input-dir", str(tmp_path / "10-merged"),
            "--verdicts-dir", str(tmp_path / "15-validation"),
            "--output-dir", str(out),
        ])
        assert result.returncode == 0, result.stderr
        _envelope, findings = _load_stage(out)
        assert len(findings) == 1
        assert findings[0]["title"] == "keep me"

