    def test_envelope_issues_accumulated(self, tmp_path: Path):
        f = _finding(chash="aaaaaaaaaaaaaaaa", title="x")
        input_dir = tmp_path / "10-merged"
        _write_stage_dir(input_dir, [f])
        with (input_dir / "_envelope.json").open("r", encoding="utf-8") as fh:
            envelope = json.load(fh)
        envelope["issues"] = [
            {"severity": "warning", "kind": "schema_rejected_input", "message": "prior issue"},
        ]
        with (input_dir / "_envelope.json").open("w", encoding="utf-8") as fh:
            json.dump(envelope, fh)

        verdicts_dir = tmp_path / "15-validation"
        verdicts_dir.mkdir()
        bad_verdict = verdicts_dir / "batch-1-output.json"
        bad_verdict.write_text("{invalid json", encoding="utf-8")

        out = tmp_path / "20-findings"
        out.mkdir()
        result = _run([
            "--input-dir", str(input_dir),
            "--verdicts-dir", str(verdicts_dir),
            "--output-dir", str(out),
        ])
        assert result.returncode == 0, result.stderr
        envelope, _findings = _load_stage(out)
        assert len(envelope["issues"]) == 2
        assert envelope["issues"][0]["kind"] == "schema_rejected_input"
        assert envelope["issues"][1]["kind"] == "validation_failed"

    def test_output_validates_against_schemas(self, tmp_path: Path):
        import jsonschema as js
        from scripts.envelope import schema_registry as sr

        f1 = _finding(chash="aaaaaaaaaaaaaaaa", title="keep")
        f2 = _finding(chash="bbbbbbbbbbbbbbbb", title="rescore")
        _write_stage_dir(tmp_path / "10-merged", [f1, f2])
        _write_verdicts(tmp_path / "15-validation", [
            {"finding_ref": {"content_hash": "aaaaaaaaaaaaaaaa"}, "action": "confirm", "reasoning": "ok"},
            {
                "finding_ref": {"content_hash": "bbbbbbbbbbbbbbbb"},
                "action": "rescore",
                "new_dimensions": {"trace_origin": "entry-point", "trace_origin_justification": "traced"},
                "reasoning": "upgraded",
            },
        ])
        out = tmp_path / "20-findings"
        out.mkdir()
        result = _run([
            "--input-dir", str(tmp_path / "10-merged"),
            "--verdicts-dir", str(tmp_path / "15-validation"),
            "--output-dir", str(out),
        ])
        assert result.returncode == 0, result.stderr

        envelope_schema = json.loads((SCHEMAS / "stage-envelope.schema.json").read_text(encoding="utf-8"))
        finding_schema = json.loads((SCHEMAS / "merged-finding.schema.json").read_text(encoding="utf-8"))
        registry = sr()
        envelope, findings = _load_stage(out)
        js.Draft202012Validator(envelope_schema, registry=registry).validate(envelope)
        for f in findings:
            js.Draft202012Validator(finding_schema, registry=registry).validate(f)
